parameters.functionCode:
// Supabase sends { type: 'INSERT', record: { id, email, ... } }
const record = $input.first().json.record;
if (!record || !record.email) return [];
return [{ json: {
  email: record.email,
  first_name: (record.raw_user_meta_data?.full_name || record.email.split('@')[0]).split(' ')[0],
  discount_code: 'WELCOME10-' + record.id.slice(0,8).toUpperCase(),
  user_id: record.id
} }];

